/**
 * Pure interpolation primitives for dynamic sliders.
 * No DOM dependency. See specs/001-dynamic-sliders/research.md §R-3.
 */

/** Locate index `i` such that `headers[i] <= x <= headers[i+1]` for monotonic-increasing
 * headers, or the symmetric span for monotonic-decreasing. Returns `-1` if `x` falls
 * outside the header range. O(log n) binary search. */
function locateSpan(headers: number[], x: number): number {
  const n = headers.length;
  if (n < 2) return -1;
  const increasing = headers[0] < headers[n - 1];
  const lo = increasing ? headers[0] : headers[n - 1];
  const hi = increasing ? headers[n - 1] : headers[0];
  if (x < lo || x > hi) return -1;

  let left = 0;
  let right = n - 1;
  while (right - left > 1) {
    const mid = (left + right) >>> 1;
    const midVal = headers[mid];
    const inLeftHalf = increasing ? x >= midVal : x <= midVal;
    if (inLeftHalf) left = mid;
    else right = mid;
  }
  return left;
}

/** Linear 1-D interpolation between two nearest header values.
 * Returns NaN if `x` is out of range or interpolation hits a non-finite cell. */
export function linear1D(headers: number[], values: number[], x: number): number {
  if (headers.length !== values.length) return NaN;
  const i = locateSpan(headers, x);
  if (i < 0) return NaN;

  const x0 = headers[i];
  const x1 = headers[i + 1];
  const y0 = values[i];
  const y1 = values[i + 1];

  if (x === x0) return y0;
  if (x === x1) return y1;
  if (!isFinite(y0) || !isFinite(y1)) return NaN;
  if (x0 === x1) return y0;

  const t = (x - x0) / (x1 - x0);
  return y0 + t * (y1 - y0);
}

/** Bilinear 2-D interpolation across the four cells surrounding (r, c).
 * `matrix[i][j]` corresponds to `rowHeaders[i]` × `colHeaders[j]`. */
export function bilinear(
  rowHeaders: number[],
  colHeaders: number[],
  matrix: number[][],
  r: number,
  c: number
): number {
  const i = locateSpan(rowHeaders, r);
  const j = locateSpan(colHeaders, c);
  if (i < 0 || j < 0) return NaN;

  const r0 = rowHeaders[i];
  const r1 = rowHeaders[i + 1];
  const c0 = colHeaders[j];
  const c1 = colHeaders[j + 1];

  const q00 = matrix[i]?.[j];
  const q01 = matrix[i]?.[j + 1];
  const q10 = matrix[i + 1]?.[j];
  const q11 = matrix[i + 1]?.[j + 1];

  if (!isFinite(q00) || !isFinite(q01) || !isFinite(q10) || !isFinite(q11)) return NaN;

  const tr = r1 === r0 ? 0 : (r - r0) / (r1 - r0);
  const tc = c1 === c0 ? 0 : (c - c0) / (c1 - c0);

  const top = q00 + tc * (q01 - q00);
  const bot = q10 + tc * (q11 - q10);
  return top + tr * (bot - top);
}
