/**
 * Axis-slider orchestrator.
 *
 * Sliders are injected DIRECTLY INTO the host table (matching the reference
 * mockups under `mockup/britain-legacy/dynamic_tables/`):
 *   - The column-axis slider lives in a prepended row that spans the column data
 *     cells (`<th colspan=N>`).
 *   - The row-axis slider lives in a `<th rowspan=N>` cell inserted at the start
 *     of the original header row, oriented vertically with `writing-mode`.
 *   - The interpolated readout occupies the new top-left corner cell, plus an
 *     optional "From equation" line below when a formula is registered.
 *   - Four surrounding cells are highlighted to show the interpolation context.
 *
 * See specs/001-dynamic-sliders/data-model.md for entity definitions.
 */

import { linear1D, bilinear } from '../utils/interpolation';
import { deriveSyncKey, parseHeaderNumber } from '../utils/sync-key';
import {
  resolveInitialPosition,
  persistPosition,
  pruneEntry,
} from '../utils/slider-persistence';
import { formatNumber } from '../ui/slider-control';

export type Axis = 'row' | 'col';

export interface AxisBinding {
  axis: Axis;
  headerValues: number[];
  monotonicity: 'increasing' | 'decreasing';
  unitSuffix: string | null;
  cellMatrix: number[][];
  rowHeaderValues: number[];
  colHeaderValues: number[];
}

/** Minimal handle exposed for legacy compatibility — the slider input + readout
 *  spans live inside the host table. */
export interface SliderHandle {
  root: HTMLElement;        // The slider <input>'s containing cell.
  input: HTMLInputElement;
  readoutInterpolated: HTMLElement; // The corner readout span (interpolated).
  readoutEquation: HTMLElement | null;
  setEquationReadout(_text: string | null): void;
  setInterpolatedReadout(_text: string): void;
  setValue(value: number, opts?: { silent?: boolean }): void;
  getValue(): number;
  destroy(): void;
}

export interface GridSightSlider {
  readonly id: string;
  readonly kind: 'axis' | 'threshold';
  readonly axis: Axis | undefined;
  position: number;
  position01: number;
  readonly tableId: string;
  readonly syncKey: string | null;
  handle: SliderHandle;
  setPosition(value: number, opts?: { silent?: boolean; broadcast?: boolean }): void;
  destroy(): void;
}

interface InternalSlider extends GridSightSlider {
  binding: AxisBinding | null;
  table: HTMLTableElement;
}

/** Per-table injection state. Built lazily on first axis slider. */
interface TableContext {
  table: HTMLTableElement;
  /** Cached original headers (read once before injection). */
  rowHeaders: string[];
  colHeaders: string[];
  /** Cached cell matrix (numeric, NaN for missing). */
  cellMatrix: number[][];
  /** Number of original data columns (excluding the row-header column). */
  dataColumnCount: number;
  /** Number of original data rows (excluding the column-header row). */
  dataRowCount: number;
  /** The injected top row (slider for col axis + corner readout). */
  topRow: HTMLTableRowElement | null;
  /** The corner cell where the interpolated readout lives. */
  cornerCell: HTMLTableCellElement | null;
  /** The injected colspan cell that hosts the column slider input. */
  colSliderCell: HTMLTableCellElement | null;
  /** The injected rowspan cell that hosts the row slider input.
   *  Rowspan = dataRowCount, anchored on the FIRST data row, so the slider's
   *  vertical extent maps 1:1 onto the data rows (FR-005 visualisation). */
  rowSliderCell: HTMLTableCellElement | null;
  /** The cell at the TOP of the slider column (in the header row), holding the
   *  row slider's "Range: <value>" readout. Aligns with the column-header row. */
  rowSliderHeaderCell: HTMLTableCellElement | null;
  /** Span elements showing the current axis slider value alongside the input. */
  colValueSpan: HTMLSpanElement | null;
  rowValueSpan: HTMLSpanElement | null;
  /** The equation-readout line under the corner readout. */
  equationLine: HTMLDivElement | null;
}

const tableContexts = new WeakMap<HTMLTableElement, TableContext>();
const sliderRegistry: InternalSlider[] = [];
const formulaRegistry = new WeakMap<HTMLTableElement, (rowVal: number, colVal: number) => number>();
const recomputeListeners = new Set<() => void>();

/**
 * Inject slider CSS once. style.css is only loaded by the dev entry
 * (`main.ts`); the published IIFE built from `index.ts` does not pull
 * style.css, so without this we'd render unstyled sliders + missing
 * highlights. Idempotent — guarded by `data-gs-slider-styles`.
 */
(function injectSliderStyles() {
  if (typeof document === 'undefined') return;
  if (document.head.querySelector('style[data-gs-slider-styles]')) return;
  const style = document.createElement('style');
  style.setAttribute('data-gs-slider-styles', '');
  style.textContent = `
    [data-gs-slider] { display:flex; align-items:center; gap:8px; padding:4px 6px; font:13px/1.2 system-ui,sans-serif; }
    [data-gs-slider][data-gs-slider-orientation="vertical"] { flex-direction:column; }

    /* Horizontal slider — custom-styled. */
    [data-gs-slider] input[type="range"],
    th[data-gs-col-slot] input[type="range"] {
      appearance: none; -webkit-appearance: none; outline: none; margin: 0;
      cursor: pointer; background: #d0d0d0; border-radius: 2px;
    }
    th[data-gs-col-slot] input[type="range"] { width: 100%; height: 4px; }

    [data-gs-slider] input[type="range"]::-webkit-slider-thumb,
    th[data-gs-col-slot] input[type="range"]::-webkit-slider-thumb {
      -webkit-appearance: none; width: 16px; height: 16px; border-radius: 50%;
      background: var(--gs-slider-thumb-color, #1976d2); cursor: pointer;
      border: 2px solid #fff; box-shadow: 0 1px 2px rgba(0,0,0,0.2);
    }
    [data-gs-slider] input[type="range"]::-moz-range-thumb,
    th[data-gs-col-slot] input[type="range"]::-moz-range-thumb {
      width: 16px; height: 16px; border-radius: 50%;
      background: var(--gs-slider-thumb-color, #1976d2); cursor: pointer;
      border: 2px solid #fff; box-shadow: 0 1px 2px rgba(0,0,0,0.2);
    }

    /* Vertical slider — let the native renderer handle styling so the thumb
       and track stay aligned. \`writing-mode: vertical-lr\` is supported in
       all evergreen browsers ≤ 2 years old; legacy WebKit also accepts
       \`-webkit-appearance: slider-vertical\` as a fallback. */
    th[data-gs-row-slot] input[type="range"] {
      -webkit-appearance: slider-vertical;
      appearance: slider-vertical;
      writing-mode: vertical-lr;
      height: 200px;
      width: 18px;
      margin: 0;
      cursor: pointer;
      outline: none;
      background: transparent;
    }
    th[data-gs-corner] { font-weight: 600; font-size: 14px; background: #f4f4f4; }
    th[data-gs-corner] [data-gs-slider-readout="interpolated"],
    th[data-gs-corner] [data-gs-slider-readout="equation"] { display: block; min-height: 1.2em; }
    th[data-gs-corner] [data-gs-slider-readout="equation"] { font-size: 11px; color: #6a1b9a; }
    th[data-gs-row-header] { background: #fafafa; }
    th[data-gs-row-slot] { background: #fafafa; }
    [data-gs-injected] { background: #fafafa; }
    td.gs-slider-highlight, th.gs-slider-highlight {
      background-color: #ffff99 !important;
      transition: background-color 80ms linear;
    }
    [data-gs-marker] {
      position: absolute; width: 14px; height: 14px; border-radius: 50%;
      border: 2px solid #1976d2; background: rgba(255,255,255,0.4);
      pointer-events: none; transform: translate(-50%, -50%); z-index: 5;
      box-shadow: 0 0 0 2px rgba(255,255,255,0.7);
      transition: top 60ms linear, left 60ms linear;
    }
    .gs-threshold-host.gs-threshold-active [data-gs-cell-fade] {
      opacity: var(--gs-cell-fade, 1); transition: opacity 80ms linear;
    }
  `;
  document.head.appendChild(style);
})();

let idCounter = 0;
function nextLocalId(): string {
  idCounter += 1;
  return String(idCounter);
}

function ensureTableId(table: HTMLTableElement): string {
  if (!table.id) table.id = `gs-tbl-${nextLocalId()}`;
  return table.id;
}

/* ────────────────────────────────────────────────────────────────────────── */
/* Axis-binding parsing — reads the table BEFORE any injection has happened.  */
/* ────────────────────────────────────────────────────────────────────────── */

function readRawAxisHeaders(table: HTMLTableElement, axis: Axis): string[] {
  // Always read from non-injected rows/cells so this works pre- AND post-
  // injection. Injected nodes carry `data-gs-injected`.
  const rows = Array.from(table.rows).filter(r => !r.hasAttribute('data-gs-injected'));
  if (axis === 'col') {
    if (!rows[0]) return [];
    const cells = Array.from(rows[0].cells).filter(c => !c.hasAttribute('data-gs-injected'));
    return cells.slice(1).map(c => c.textContent?.trim() ?? '');
  }
  // axis === 'row'
  const out: string[] = [];
  for (let i = 1; i < rows.length; i++) {
    const cells = Array.from(rows[i].cells).filter(c => !c.hasAttribute('data-gs-injected'));
    if (cells.length === 0) continue;
    out.push(cells[0].textContent?.trim() ?? '');
  }
  return out;
}

function readRawCellMatrix(table: HTMLTableElement): number[][] {
  const rows = Array.from(table.rows).filter(r => !r.hasAttribute('data-gs-injected'));
  const out: number[][] = [];
  for (let i = 1; i < rows.length; i++) {
    const cells = Array.from(rows[i].cells).filter(c => !c.hasAttribute('data-gs-injected'));
    const row: number[] = [];
    for (let j = 1; j < cells.length; j++) {
      const t = cells[j].textContent?.trim() ?? '';
      const n = parseHeaderNumber(t);
      row.push(n === null ? NaN : n);
    }
    out.push(row);
  }
  return out;
}

function detectMonotonicity(values: number[]): 'increasing' | 'decreasing' | null {
  if (values.length < 2) return null;
  let inc = true, dec = true;
  for (let i = 1; i < values.length; i++) {
    if (values[i] <= values[i - 1]) inc = false;
    if (values[i] >= values[i - 1]) dec = false;
  }
  if (inc) return 'increasing';
  if (dec) return 'decreasing';
  return null;
}

function detectUnitSuffix(headerTexts: string[]): string | null {
  for (const t of headerTexts) {
    const m = t.trim().match(/^-?[\d.,eE+-]+(?:\.[\d]+)?\s*([a-zA-Z%]+(?:\/[a-zA-Z]+)?)$/);
    if (m) return m[1];
  }
  return null;
}

export function buildAxisBinding(table: HTMLTableElement, axis: Axis): AxisBinding | null {
  const headerTexts = readRawAxisHeaders(table, axis);
  if (headerTexts.length < 2) return null;
  const headerValues: number[] = [];
  for (const t of headerTexts) {
    const n = parseHeaderNumber(t);
    if (n === null) return null;
    headerValues.push(n);
  }
  const mono = detectMonotonicity(headerValues);
  if (mono === null) return null;
  const cellMatrix = readRawCellMatrix(table);

  const rowHeaderTexts = readRawAxisHeaders(table, 'row');
  const colHeaderTexts = readRawAxisHeaders(table, 'col');
  const rowHeaderValues = rowHeaderTexts.map(t => parseHeaderNumber(t) ?? NaN);
  const colHeaderValues = colHeaderTexts.map(t => parseHeaderNumber(t) ?? NaN);

  return {
    axis,
    headerValues,
    monotonicity: mono,
    unitSuffix: detectUnitSuffix(headerTexts),
    cellMatrix,
    rowHeaderValues,
    colHeaderValues,
  };
}

/* ────────────────────────────────────────────────────────────────────────── */
/* Injection                                                                  */
/* ────────────────────────────────────────────────────────────────────────── */

function ensureInjection(table: HTMLTableElement): TableContext {
  let ctx = tableContexts.get(table);
  if (ctx) return ctx;

  // Read original structure BEFORE injecting.
  const colHeaders = readRawAxisHeaders(table, 'col');
  const rowHeaders = readRawAxisHeaders(table, 'row');
  const cellMatrix = readRawCellMatrix(table);
  const dataColumnCount = colHeaders.length;
  const dataRowCount = rowHeaders.length;

  ctx = {
    table,
    rowHeaders,
    colHeaders,
    cellMatrix,
    dataColumnCount,
    dataRowCount,
    topRow: null,
    cornerCell: null,
    colSliderCell: null,
    rowSliderCell: null,
    rowSliderHeaderCell: null,
    colValueSpan: null,
    rowValueSpan: null,
    equationLine: null,
  };

  // Tag every original data cell with row/col index for highlighting.
  const originalRows = Array.from(table.rows).filter(r => !r.hasAttribute('data-gs-injected'));
  for (let i = 1; i < originalRows.length; i++) {
    const cells = Array.from(originalRows[i].cells).filter(c => !c.hasAttribute('data-gs-injected'));
    for (let j = 1; j < cells.length; j++) {
      cells[j].setAttribute('data-gs-rc', `${i - 1}:${j - 1}`);
    }
  }

  tableContexts.set(table, ctx);
  return ctx;
}

function ensureTopRow(ctx: TableContext): HTMLTableRowElement {
  if (ctx.topRow) return ctx.topRow;

  // Build: <tr data-gs-injected>
  //          <th data-gs-injected data-gs-corner>readout</th>
  //          <th data-gs-injected colspan=dataColumnCount data-gs-col-slot></th>
  //        </tr>
  // Note: when a row slider is later added, an additional rowspan TH will be
  // inserted at position 0 of row 1 (the original header row), aligning with
  // this top row's corner cell visually as a 1-column-wide leftmost column.

  const tr = document.createElement('tr');
  tr.setAttribute('data-gs-injected', '');

  const corner = document.createElement('th');
  corner.setAttribute('data-gs-injected', '');
  corner.setAttribute('data-gs-corner', '');
  corner.style.minWidth = '7ch';
  corner.style.fontVariantNumeric = 'tabular-nums';
  corner.style.textAlign = 'center';
  // Initially colspan=1 to match the original header row's leading cell (the
  // corner-label cell). When a row slider is later added, the header row gains
  // a leading rowSliderTH cell, and we bump corner.colSpan to 2 so the top row
  // total stays aligned with the (wider) header row.
  corner.colSpan = 1;
  const interp = document.createElement('div');
  interp.setAttribute('data-gs-slider-readout', 'interpolated');
  interp.setAttribute('aria-live', 'polite');
  interp.setAttribute('role', 'status');
  interp.textContent = '—';
  corner.appendChild(interp);

  const colSlot = document.createElement('th');
  colSlot.setAttribute('data-gs-injected', '');
  colSlot.setAttribute('data-gs-col-slot', '');
  colSlot.colSpan = ctx.dataColumnCount;
  colSlot.style.padding = '4px 8px';

  tr.appendChild(corner);
  tr.appendChild(colSlot);

  // Insert before the first non-injected row (the original header row).
  const firstOriginal = Array.from(ctx.table.rows).find(r => !r.hasAttribute('data-gs-injected'));
  const tbody = ctx.table.tBodies[0] || ctx.table;
  if (firstOriginal) {
    firstOriginal.parentElement!.insertBefore(tr, firstOriginal);
  } else {
    tbody.appendChild(tr);
  }

  ctx.topRow = tr;
  ctx.cornerCell = corner;
  ctx.colSliderCell = colSlot;
  return tr;
}

function ensureRowSliderSlot(ctx: TableContext): HTMLTableCellElement {
  if (ctx.rowSliderCell) return ctx.rowSliderCell;

  // The slider column gains TWO new cells:
  //   (a) A readout cell in the header row — same vertical position as
  //       "Range ↓ / SL →" / "10" / "20" / ...  (holds "Range: <value>").
  //   (b) A `rowspan = dataRowCount` cell anchored on the first data row,
  //       hosting the vertical slider input. Bound only over the data rows
  //       so the thumb's vertical position aligns with the row labels.

  const headerRow = Array.from(ctx.table.rows).find(r => !r.hasAttribute('data-gs-injected'));
  if (!headerRow) throw new Error('No original header row found');

  // Header-row readout cell.
  const headerCell = document.createElement('th');
  headerCell.setAttribute('data-gs-injected', '');
  headerCell.setAttribute('data-gs-row-header', '');
  headerCell.style.padding = '6px';
  headerCell.style.verticalAlign = 'middle';
  headerCell.style.textAlign = 'center';
  headerCell.style.minWidth = '4ch';
  headerRow.insertBefore(headerCell, headerRow.firstChild);

  // Slider cell — rowspan over data rows only.
  const cell = document.createElement('th');
  cell.setAttribute('data-gs-injected', '');
  cell.setAttribute('data-gs-row-slot', '');
  cell.rowSpan = Math.max(1, ctx.dataRowCount);
  cell.style.padding = '6px';
  cell.style.verticalAlign = 'middle';
  cell.style.textAlign = 'center';

  // Anchor the slider TH on the first data row.
  const firstDataRow = headerRow.nextElementSibling as HTMLTableRowElement | null;
  if (firstDataRow) {
    firstDataRow.insertBefore(cell, firstDataRow.firstChild);
  } else {
    headerRow.parentElement!.appendChild(cell);
  }

  // The header row gained a leading cell — keep the top row aligned.
  if (ctx.cornerCell) ctx.cornerCell.colSpan = 2;

  ctx.rowSliderCell = cell;
  ctx.rowSliderHeaderCell = headerCell;
  return cell;
}

function tearDownInjectionIfEmpty(ctx: TableContext): void {
  const hasSliderForTable = sliderRegistry.some(s => s.kind === 'axis' && s.table === ctx.table);
  if (hasSliderForTable) return;

  // Remove highlight + axis-row-col tags.
  for (const cell of ctx.table.querySelectorAll<HTMLElement>('[data-gs-rc]')) {
    cell.removeAttribute('data-gs-rc');
    cell.classList.remove('gs-slider-highlight');
  }
  ctx.topRow?.parentElement?.removeChild(ctx.topRow);
  ctx.rowSliderCell?.parentElement?.removeChild(ctx.rowSliderCell);
  ctx.rowSliderHeaderCell?.parentElement?.removeChild(ctx.rowSliderHeaderCell);
  tableContexts.delete(ctx.table);
}

/* ────────────────────────────────────────────────────────────────────────── */
/* Recompute pipeline                                                         */
/* ────────────────────────────────────────────────────────────────────────── */

function getAxisSlidersForTable(table: HTMLTableElement): InternalSlider[] {
  return sliderRegistry.filter(s => s.kind === 'axis' && s.table === table);
}

function bracketIndices(headers: number[], x: number): [number, number] | null {
  const n = headers.length;
  if (n < 2) return null;
  const inc = headers[0] < headers[n - 1];
  const lo = inc ? headers[0] : headers[n - 1];
  const hi = inc ? headers[n - 1] : headers[0];
  if (x < lo || x > hi) return null;
  let left = 0, right = n - 1;
  while (right - left > 1) {
    const mid = (left + right) >>> 1;
    const inLeft = inc ? x >= headers[mid] : x <= headers[mid];
    if (inLeft) left = mid; else right = mid;
  }
  return [left, right];
}

function highlightCells(ctx: TableContext, rowPos: number | null, colPos: number | null): void {
  for (const cell of ctx.table.querySelectorAll<HTMLElement>('.gs-slider-highlight')) {
    cell.classList.remove('gs-slider-highlight');
  }
  // Need both axes' brackets (use midpoint header value on the missing axis).
  const rowBr = rowPos !== null
    ? bracketIndices(ctx.cellMatrix.length ? ctx.cellMatrix.map((_, i) => i).map(i => i) : [], 0) // placeholder, replaced below
    : null;
  void rowBr;

  const rowHeaderValues = ctx.rowHeaders.map(t => parseHeaderNumber(t) ?? NaN);
  const colHeaderValues = ctx.colHeaders.map(t => parseHeaderNumber(t) ?? NaN);

  const rPair = rowPos !== null ? bracketIndices(rowHeaderValues, rowPos) : null;
  const cPair = colPos !== null ? bracketIndices(colHeaderValues, colPos) : null;

  if (rPair && cPair) {
    for (const ri of rPair) for (const ci of cPair) {
      const cell = ctx.table.querySelector<HTMLElement>(`[data-gs-rc="${ri}:${ci}"]`);
      if (cell) cell.classList.add('gs-slider-highlight');
    }
  } else if (rPair) {
    for (const ri of rPair) {
      const cells = ctx.table.querySelectorAll<HTMLElement>(`[data-gs-rc^="${ri}:"]`);
      cells.forEach(c => c.classList.add('gs-slider-highlight'));
    }
  } else if (cPair) {
    for (const ci of cPair) {
      ctx.table.querySelectorAll<HTMLElement>('[data-gs-rc]').forEach((c) => {
        const rc = c.getAttribute('data-gs-rc') ?? '';
        if (rc.endsWith(':' + ci)) c.classList.add('gs-slider-highlight');
      });
    }
  }
}

function refreshTableReadouts(table: HTMLTableElement): void {
  const ctx = tableContexts.get(table);
  if (!ctx) return;
  const axes = getAxisSlidersForTable(table);
  const rowSlider = axes.find(s => s.axis === 'row') ?? null;
  const colSlider = axes.find(s => s.axis === 'col') ?? null;
  const rowPos = rowSlider ? rowSlider.position : null;
  const colPos = colSlider ? colSlider.position : null;

  // Update value labels alongside the inputs.
  if (ctx.colValueSpan && colSlider) ctx.colValueSpan.textContent = formatNumber(colSlider.position);
  if (ctx.rowValueSpan && rowSlider) ctx.rowValueSpan.textContent = formatNumber(rowSlider.position);

  // Compute interpolated readout (corner cell).
  let interpText = '—';
  if (rowSlider && colSlider) {
    const v = bilinear(
      ctx.rowHeaders.map(t => parseHeaderNumber(t) ?? NaN),
      ctx.colHeaders.map(t => parseHeaderNumber(t) ?? NaN),
      ctx.cellMatrix,
      rowSlider.position,
      colSlider.position
    );
    if (isFinite(v)) interpText = formatNumber(v);
  } else if (rowSlider) {
    // 1-D along the row axis at the column-midpoint.
    const cm = ctx.colHeaders.map(t => parseHeaderNumber(t) ?? NaN);
    const colMid = cm.length >= 2 ? (cm[0] + cm[cm.length - 1]) / 2 : (cm[0] || 0);
    const v = bilinear(
      ctx.rowHeaders.map(t => parseHeaderNumber(t) ?? NaN),
      cm, ctx.cellMatrix, rowSlider.position, colMid
    );
    if (isFinite(v)) interpText = formatNumber(v);
    void linear1D;
  } else if (colSlider) {
    const rm = ctx.rowHeaders.map(t => parseHeaderNumber(t) ?? NaN);
    const rowMid = rm.length >= 2 ? (rm[0] + rm[rm.length - 1]) / 2 : (rm[0] || 0);
    const v = bilinear(
      rm, ctx.colHeaders.map(t => parseHeaderNumber(t) ?? NaN),
      ctx.cellMatrix, rowMid, colSlider.position
    );
    if (isFinite(v)) interpText = formatNumber(v);
  }
  if (ctx.cornerCell) {
    const interpEl = ctx.cornerCell.querySelector('[data-gs-slider-readout="interpolated"]');
    if (interpEl) interpEl.textContent = interpText;
  }

  // Equation readout (Story 2).
  const formula = formulaRegistry.get(table);
  if (formula) {
    const rv = rowPos ?? (ctx.rowHeaders.length
      ? (parseHeaderNumber(ctx.rowHeaders[0]) ?? 0)
      : 0);
    const cv = colPos ?? (ctx.colHeaders.length
      ? (parseHeaderNumber(ctx.colHeaders[0]) ?? 0)
      : 0);
    let eqText = '—';
    try {
      const result = formula(rv, cv);
      if (isFinite(result)) eqText = formatNumber(result);
    } catch (err) {
      console.warn('[gridSight] formula threw:', err);
    }
    if (ctx.cornerCell) {
      if (!ctx.equationLine) {
        ctx.equationLine = document.createElement('div');
        ctx.equationLine.setAttribute('data-gs-slider-readout', 'equation');
        ctx.equationLine.setAttribute('aria-live', 'polite');
        ctx.equationLine.style.fontSize = '11px';
        ctx.equationLine.style.color = '#6a1b9a';
        ctx.cornerCell.appendChild(ctx.equationLine);
      }
      ctx.equationLine.textContent = eqText;
    }
  } else if (ctx.equationLine) {
    ctx.equationLine.remove();
    ctx.equationLine = null;
  }

  // Highlight surrounding cells.
  highlightCells(ctx, rowPos, colPos);

  for (const cb of recomputeListeners) {
    try { cb(); } catch (err) { console.warn(err); }
  }
}

function broadcastSync(driver: InternalSlider): void {
  if (!driver.syncKey) return;
  if (driver.table.hasAttribute('data-gs-no-sync')) return;
  for (const s of sliderRegistry) {
    if (s === driver) continue;
    if (s.kind !== 'axis') continue;
    if (s.syncKey !== driver.syncKey) continue;
    if (s.table.hasAttribute('data-gs-no-sync')) continue;
    if (s.position !== driver.position) {
      s.setPosition(driver.position, { silent: false, broadcast: false });
    }
  }
}

/* ────────────────────────────────────────────────────────────────────────── */
/* Slider input creation + wiring                                             */
/* ────────────────────────────────────────────────────────────────────────── */

function createSliderInput(opts: {
  id: string,
  min: number,
  max: number,
  initial: number,
  axis: Axis,
  ariaLabel: string,
}): HTMLInputElement {
  const input = document.createElement('input');
  input.type = 'range';
  input.min = String(opts.min);
  input.max = String(opts.max);
  input.step = 'any';
  input.value = String(Math.min(opts.max, Math.max(opts.min, opts.initial)));
  input.id = `gs-slider-${opts.id.replace(/[^a-zA-Z0-9_-]/g, '_')}`;
  input.setAttribute('aria-label', opts.ariaLabel);
  input.setAttribute('data-gs-slider-input', opts.axis);
  // Sizing & orientation come from injected CSS (see injectSliderStyles).
  // Firefox also honours the `orient` attribute for vertical sliders.
  if (opts.axis === 'row') {
    input.setAttribute('orient', 'vertical');
  }
  return input;
}

/* ────────────────────────────────────────────────────────────────────────── */
/* Public API                                                                 */
/* ────────────────────────────────────────────────────────────────────────── */

export function addSlider(table: HTMLTableElement, axis: Axis): GridSightSlider {
  if (!table) throw new Error('No table');
  ensureTableId(table);

  const existing = sliderRegistry.find(s => s.kind === 'axis' && s.table === table && s.axis === axis);
  if (existing) throw new Error('Slider already exists');

  const binding = buildAxisBinding(table, axis);
  if (!binding) throw new Error('Axis not numeric');

  const ctx = ensureInjection(table);

  const min = Math.min(...binding.headerValues);
  const max = Math.max(...binding.headerValues);
  const id = `${table.id}#${axis}`;
  const initialPos01 = resolveInitialPosition(id);
  const initial = min + initialPos01 * (max - min);
  const syncKey = deriveSyncKey([...binding.headerValues].map(String));

  // Build the slot if needed.
  const ariaLabel = `${axis === 'row' ? 'Row' : 'Column'} slider (${formatNumber(min)}–${formatNumber(max)})`;
  const input = createSliderInput({ id, min, max, initial, axis, ariaLabel });

  // Surrounding label span.
  const valueSpan = document.createElement('span');
  valueSpan.style.fontVariantNumeric = 'tabular-nums';
  valueSpan.style.fontSize = '12px';
  valueSpan.textContent = formatNumber(initial);

  if (axis === 'col') {
    ensureTopRow(ctx);
    const slot = ctx.colSliderCell!;
    slot.innerHTML = '';
    slot.appendChild(input);
    const label = document.createElement('div');
    label.style.fontSize = '11px';
    label.style.color = '#444';
    label.textContent = 'SL: ';
    label.appendChild(valueSpan);
    slot.appendChild(label);
    ctx.colValueSpan = valueSpan;
  } else {
    ensureTopRow(ctx);
    const slot = ensureRowSliderSlot(ctx);
    slot.innerHTML = '';
    slot.appendChild(input);
    // Row-axis readout lives in the new top-of-column header cell, NOT below
    // the input — that way the slider's rowspan extent maps cleanly onto the
    // data rows and aligns with row labels.
    const headerCell = ctx.rowSliderHeaderCell!;
    headerCell.innerHTML = '';
    const label = document.createElement('div');
    label.style.fontSize = '11px';
    label.style.color = '#444';
    label.textContent = 'Range: ';
    label.appendChild(valueSpan);
    headerCell.appendChild(label);
    ctx.rowValueSpan = valueSpan;
  }

  // RAF-throttled value handler.
  let pendingValue: number | null = null;
  let scheduled = false;
  const fireUpdate = (v: number) => {
    slider.position = v;
    slider.position01 = (v - min) / (max - min);
    valueSpan.textContent = formatNumber(v);
    refreshTableReadouts(table);
    persistPosition(id, slider.position01);
    broadcastSync(slider);
  };
  const flush = () => {
    scheduled = false;
    if (pendingValue !== null) {
      const v = pendingValue;
      pendingValue = null;
      fireUpdate(v);
    }
  };
  const schedule = (v: number) => {
    pendingValue = v;
    if (scheduled) return;
    scheduled = true;
    requestAnimationFrame(flush);
  };

  input.addEventListener('input', () => {
    const v = parseFloat(input.value);
    if (isFinite(v)) schedule(v);
  });

  input.addEventListener('keydown', (ev: KeyboardEvent) => {
    const range = max - min;
    if (range <= 0) return;
    let next: number | null = null;
    const cur = parseFloat(input.value);
    switch (ev.key) {
      case 'ArrowRight':
      case 'ArrowUp':
        next = cur + range * 0.01; break;
      case 'ArrowLeft':
      case 'ArrowDown':
        next = cur - range * 0.01; break;
      case 'PageUp':   next = cur + range * 0.1;  break;
      case 'PageDown': next = cur - range * 0.1;  break;
      case 'Home':     next = min;                break;
      case 'End':      next = max;                break;
      default: return;
    }
    ev.preventDefault();
    next = Math.min(max, Math.max(min, next));
    input.value = String(next);
    schedule(next);
  });

  // Build the SliderHandle for legacy compatibility.
  const handle: SliderHandle = {
    root: input.parentElement!,
    input,
    get readoutInterpolated() {
      return (ctx.cornerCell?.querySelector('[data-gs-slider-readout="interpolated"]') as HTMLElement) || ctx.cornerCell!;
    },
    get readoutEquation() {
      return ctx.equationLine;
    },
    setEquationReadout: (text: string | null) => {
      // Equation readout is managed by refreshTableReadouts; this is a no-op
      // shim retained for older tests calling it directly.
      void text;
    },
    setInterpolatedReadout: (text: string) => {
      const el = ctx.cornerCell?.querySelector('[data-gs-slider-readout="interpolated"]');
      if (el) el.textContent = text;
    },
    setValue: (value: number, options?: { silent?: boolean }) => {
      const v = Math.min(max, Math.max(min, value));
      input.value = String(v);
      if (!options?.silent) schedule(v);
    },
    getValue: () => parseFloat(input.value),
    destroy: () => { /* handled by slider.destroy() */ },
  };

  const slider: InternalSlider = {
    id,
    kind: 'axis',
    axis,
    tableId: table.id,
    syncKey,
    table,
    binding,
    position: initial,
    position01: initialPos01,
    handle,
    setPosition(value: number, opts) {
      const clamped = Math.min(max, Math.max(min, value));
      slider.position = clamped;
      slider.position01 = (clamped - min) / (max - min);
      input.value = String(clamped);
      valueSpan.textContent = formatNumber(clamped);
      refreshTableReadouts(table);
      persistPosition(id, slider.position01);
      if (opts?.broadcast !== false) broadcastSync(slider);
    },
    destroy() {
      const idx = sliderRegistry.indexOf(slider);
      if (idx >= 0) sliderRegistry.splice(idx, 1);
      if (axis === 'row') {
        // Remove BOTH the rowSliderTH (data-row rowspan) and the header-row
        // readout cell, then revert the corner colspan.
        if (ctx.rowSliderCell && ctx.rowSliderCell.parentElement) {
          ctx.rowSliderCell.parentElement.removeChild(ctx.rowSliderCell);
        }
        if (ctx.rowSliderHeaderCell && ctx.rowSliderHeaderCell.parentElement) {
          ctx.rowSliderHeaderCell.parentElement.removeChild(ctx.rowSliderHeaderCell);
        }
        ctx.rowSliderCell = null;
        ctx.rowSliderHeaderCell = null;
        ctx.rowValueSpan = null;
        if (ctx.cornerCell) ctx.cornerCell.colSpan = 1;
      } else {
        // Empty the column-slider slot but leave the slot in place.
        if (ctx.colSliderCell) ctx.colSliderCell.innerHTML = '';
        ctx.colValueSpan = null;
      }
      pruneEntry(id);
      tearDownInjectionIfEmpty(ctx);
    },
  };

  sliderRegistry.push(slider);
  refreshTableReadouts(table);
  return slider;
}

export function getSliders(table?: HTMLTableElement): GridSightSlider[] {
  if (!table) return sliderRegistry.slice();
  return sliderRegistry.filter(s => s.table === table);
}

export function removeAllSliders(table?: HTMLTableElement): void {
  const toRemove = table ? sliderRegistry.filter(s => s.table === table) : sliderRegistry.slice();
  for (const s of toRemove) s.destroy();
}

export function registerFormula(table: HTMLTableElement, fn: (rowValue: number, colValue: number) => number): void {
  if (typeof fn !== 'function') throw new Error('Formula must be a function');
  formulaRegistry.set(table, fn);
  refreshTableReadouts(table);
}

export function clearFormula(table: HTMLTableElement): void {
  formulaRegistry.delete(table);
  refreshTableReadouts(table);
}

export function onSliderRecompute(cb: () => void): () => void {
  recomputeListeners.add(cb);
  return () => recomputeListeners.delete(cb);
}

export function inspectAxisBinding(table: HTMLTableElement, axis: Axis): AxisBinding | null {
  return buildAxisBinding(table, axis);
}

/** Internal: external slider (e.g. threshold) registration. */
export function registerExternalSlider(slider: GridSightSlider, table: HTMLTableElement): void {
  const internal = slider as InternalSlider;
  internal.table = table;
  internal.binding = null;
  sliderRegistry.push(internal);
}

export function unregisterExternalSlider(slider: GridSightSlider): void {
  const idx = sliderRegistry.indexOf(slider as InternalSlider);
  if (idx >= 0) sliderRegistry.splice(idx, 1);
}
